public class RefTypes {
    static void increment(int[] arr) { arr[0]++; }
    static void replace(int[] arr) { arr = new int[]{99}; }  // rebinds local
    public static void main(String[] args) {
        int[] a = {1, 2, 3};
        increment(a);
        System.out.println(a[0]);
        replace(a);
        System.out.println(a[0]);
    }
}
